:root {
  color-scheme: dark;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  background: #05070d;
  color: #f4fbff;
}

* {
  box-sizing: border-box;
}

body {
  min-height: 100vh;
  margin: 0;
  display: grid;
  place-items: center;
  overflow: hidden;
  background:
    radial-gradient(circle at 25% 18%, rgba(0, 232, 255, 0.16), transparent 29rem),
    radial-gradient(circle at 80% 80%, rgba(255, 58, 91, 0.12), transparent 26rem),
    linear-gradient(135deg, #05070d 0%, #0a1020 46%, #061316 100%);
}

.game-shell {
  width: min(100vw, 1080px);
  padding: 18px;
}

.stage-wrap {
  position: relative;
  overflow: hidden;
  border: 1px solid rgba(139, 241, 255, 0.32);
  border-radius: 8px;
  background: #060a12;
  box-shadow: 0 18px 70px rgba(0, 0, 0, 0.48), 0 0 38px rgba(30, 220, 255, 0.12);
}

canvas {
  display: block;
  width: 100%;
  aspect-ratio: 16 / 9;
  background: #05070d;
}

.hud {
  position: absolute;
  inset: 14px 14px auto 14px;
  display: flex;
  gap: 10px;
  pointer-events: none;
}

.hud > div {
  min-width: 96px;
  padding: 8px 10px;
  border: 1px solid rgba(184, 247, 255, 0.2);
  border-radius: 8px;
  background: rgba(5, 10, 18, 0.74);
  backdrop-filter: blur(10px);
}

.hud-label {
  display: block;
  margin-bottom: 2px;
  color: #91a6b3;
  font-size: 11px;
  text-transform: uppercase;
}

.hud strong {
  font-size: 18px;
  line-height: 1;
}

.overlay {
  position: absolute;
  inset: 0;
  display: grid;
  align-content: center;
  justify-items: center;
  gap: 16px;
  padding: 28px;
  text-align: center;
  background: rgba(3, 6, 12, 0.66);
  backdrop-filter: blur(8px);
}

.overlay.hidden {
  display: none;
}

.eyebrow {
  margin: 0;
  color: #76efff;
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 0;
  text-transform: uppercase;
}

h1,
h2 {
  max-width: 720px;
  margin: 0;
  color: #ffffff;
  font-size: clamp(42px, 7vw, 84px);
  line-height: 0.95;
  text-shadow: 0 0 30px rgba(0, 232, 255, 0.36);
}

h2 {
  font-size: clamp(34px, 6vw, 66px);
}

.intro {
  max-width: 560px;
  margin: 0;
  color: #c5d3dc;
  font-size: 17px;
  line-height: 1.55;
}

.control-grid {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 8px;
}

.control-grid span {
  padding: 8px 11px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  border-radius: 8px;
  color: #d9f9ff;
  background: rgba(255, 255, 255, 0.07);
  font-size: 13px;
  font-weight: 700;
}

button {
  min-width: 146px;
  min-height: 44px;
  border: 0;
  border-radius: 8px;
  color: #021014;
  background: linear-gradient(135deg, #76efff, #f6ff80);
  font: inherit;
  font-weight: 900;
  cursor: pointer;
  box-shadow: 0 12px 28px rgba(0, 232, 255, 0.2);
}

button:hover,
button:focus-visible {
  transform: translateY(-1px);
  outline: 2px solid rgba(255, 255, 255, 0.7);
  outline-offset: 3px;
}

footer {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 12px;
  padding: 12px 4px 0;
  color: #92a7b4;
  font-size: 13px;
}

@media (max-width: 640px) {
  body {
    place-items: start center;
    overflow-y: auto;
  }

  .game-shell {
    padding: 10px;
  }

  .hud {
    inset: 8px 8px auto 8px;
  }

  .hud > div {
    min-width: 0;
    flex: 1;
    padding: 7px 8px;
  }

  .hud strong {
    font-size: 15px;
  }

  .overlay {
    padding: 18px;
  }

  .intro {
    font-size: 15px;
  }
}

"use strict";

const canvas = document.getElementById("gameCanvas");
const ctx = canvas.getContext("2d");

const titleScreen = document.getElementById("titleScreen");
const gameOverScreen = document.getElementById("gameOverScreen");
const startButton = document.getElementById("startButton");
const restartButton = document.getElementById("restartButton");
const scoreEl = document.getElementById("score");
const bestScoreEl = document.getElementById("bestScore");
const shieldStatusEl = document.getElementById("shieldStatus");
const finalScoreEl = document.getElementById("finalScore");

const WIDTH = canvas.width;
const HEIGHT = canvas.height;
const STORAGE_KEY = "lumorix-dropdash-best";
const keys = new Set();

function loadBestScore() {
  try {
    return Number(localStorage.getItem(STORAGE_KEY) || 0);
  } catch {
    return 0;
  }
}

function saveBestScore(score) {
  try {
    localStorage.setItem(STORAGE_KEY, String(score));
  } catch {
    // Some locked-down file origins disable storage. The run still plays normally.
  }
}

const state = {
  mode: "title",
  score: 0,
  best: loadBestScore(),
  time: 0,
  spawnTimer: 0,
  coreTimer: 0,
  pulseCooldown: 0,
  pulseTime: 0,
  shake: 0,
  player: { x: WIDTH / 2 - 18, y: HEIGHT - 74, w: 36, h: 36, vx: 0 },
  hazards: [],
  cores: [],
  sparks: [],
  stars: Array.from({ length: 96 }, () => ({
    x: Math.random() * WIDTH,
    y: Math.random() * HEIGHT,
    s: 0.6 + Math.random() * 1.9,
    v: 18 + Math.random() * 58
  }))
};

bestScoreEl.textContent = state.best;

function resetGame() {
  state.mode = "playing";
  state.score = 0;
  state.time = 0;
  state.spawnTimer = 0;
  state.coreTimer = 1.2;
  state.pulseCooldown = 0;
  state.pulseTime = 0;
  state.shake = 0;
  state.hazards = [];
  state.cores = [];
  state.sparks = [];
  state.player.x = WIDTH / 2 - state.player.w / 2;
  state.player.y = HEIGHT - 74;
  state.player.vx = 0;
  titleScreen.classList.add("hidden");
  gameOverScreen.classList.add("hidden");
}

function gameOver() {
  state.mode = "over";
  state.shake = 14;
  state.best = Math.max(state.best, Math.floor(state.score));
  saveBestScore(state.best);
  bestScoreEl.textContent = state.best;
  finalScoreEl.textContent = `Score ${Math.floor(state.score)}`;
  gameOverScreen.classList.remove("hidden");
}

function spawnHazard() {
  const size = 24 + Math.random() * 28;
  const speed = 160 + Math.min(210, state.time * 9) + Math.random() * 70;
  state.hazards.push({
    x: 22 + Math.random() * (WIDTH - 44 - size),
    y: -size,
    w: size,
    h: size,
    rot: Math.random() * Math.PI,
    spin: -2 + Math.random() * 4,
    speed
  });
}

function spawnCore() {
  state.cores.push({
    x: 28 + Math.random() * (WIDTH - 56),
    y: -24,
    r: 12,
    speed: 125 + Math.random() * 70,
    wobble: Math.random() * Math.PI * 2
  });
}

function addSparks(x, y, color, count) {
  for (let i = 0; i < count; i += 1) {
    const angle = Math.random() * Math.PI * 2;
    const speed = 60 + Math.random() * 180;
    state.sparks.push({
      x,
      y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      life: 0.35 + Math.random() * 0.35,
      age: 0,
      color
    });
  }
}

function rectsOverlap(a, b) {
  return a.x < b.x + b.w && a.x + a.w > b.x && a.y < b.y + b.h && a.y + a.h > b.y;
}

function circleRectOverlap(circle, rect) {
  const cx = Math.max(rect.x, Math.min(circle.x, rect.x + rect.w));
  const cy = Math.max(rect.y, Math.min(circle.y, rect.y + rect.h));
  const dx = circle.x - cx;
  const dy = circle.y - cy;
  return dx * dx + dy * dy < circle.r * circle.r;
}

function pulse() {
  if (state.mode !== "playing" || state.pulseCooldown > 0) {
    return;
  }
  state.pulseCooldown = 5.5;
  state.pulseTime = 0.45;
  state.shake = 4;
  addSparks(state.player.x + state.player.w / 2, state.player.y + state.player.h / 2, "#76efff", 22);
}

function update(dt) {
  state.stars.forEach((star) => {
    star.y += star.v * dt;
    if (star.y > HEIGHT) {
      star.x = Math.random() * WIDTH;
      star.y = -8;
    }
  });

  state.sparks = state.sparks.filter((spark) => {
    spark.age += dt;
    spark.x += spark.vx * dt;
    spark.y += spark.vy * dt;
    spark.vx *= 0.98;
    spark.vy *= 0.98;
    return spark.age < spark.life;
  });

  if (state.mode !== "playing") {
    state.shake = Math.max(0, state.shake - dt * 25);
    return;
  }

  state.time += dt;
  state.score += dt * 12;
  state.spawnTimer -= dt;
  state.coreTimer -= dt;
  state.pulseCooldown = Math.max(0, state.pulseCooldown - dt);
  state.pulseTime = Math.max(0, state.pulseTime - dt);
  state.shake = Math.max(0, state.shake - dt * 28);

  const left = keys.has("arrowleft") || keys.has("a");
  const right = keys.has("arrowright") || keys.has("d");
  const target = (right ? 1 : 0) - (left ? 1 : 0);
  state.player.vx += (target * 520 - state.player.vx) * Math.min(1, dt * 10);
  state.player.x += state.player.vx * dt;
  state.player.x = Math.max(16, Math.min(WIDTH - state.player.w - 16, state.player.x));

  if (state.spawnTimer <= 0) {
    spawnHazard();
    state.spawnTimer = Math.max(0.24, 0.82 - state.time * 0.012);
  }

  if (state.coreTimer <= 0) {
    spawnCore();
    state.coreTimer = 2.4 + Math.random() * 1.1;
  }

  const pulseBox = {
    x: state.player.x - 42,
    y: state.player.y - 42,
    w: state.player.w + 84,
    h: state.player.h + 84
  };

  state.hazards = state.hazards.filter((hazard) => {
    hazard.y += hazard.speed * dt;
    hazard.rot += hazard.spin * dt;

    if (state.pulseTime > 0 && rectsOverlap(hazard, pulseBox)) {
      state.score += 8;
      addSparks(hazard.x + hazard.w / 2, hazard.y + hazard.h / 2, "#ff4160", 10);
      return false;
    }

    if (rectsOverlap(hazard, state.player)) {
      gameOver();
    }
    return hazard.y < HEIGHT + 80;
  });

  state.cores = state.cores.filter((core) => {
    core.y += core.speed * dt;
    core.wobble += dt * 4;
    const liveCore = { x: core.x + Math.sin(core.wobble) * 8, y: core.y, r: core.r };
    if (circleRectOverlap(liveCore, state.player)) {
      state.score += 50;
      state.pulseCooldown = Math.max(0, state.pulseCooldown - 1.4);
      addSparks(liveCore.x, liveCore.y, "#76efff", 18);
      return false;
    }
    return core.y < HEIGHT + 40;
  });
}

function drawPlayer() {
  const p = state.player;
  const glow = state.pulseTime > 0 ? 28 : 12;
  ctx.save();
  ctx.translate(p.x + p.w / 2, p.y + p.h / 2);
  ctx.shadowColor = "#76efff";
  ctx.shadowBlur = glow;
  ctx.fillStyle = "#effcff";
  ctx.fillRect(-p.w / 2, -p.h / 2, p.w, p.h);
  ctx.fillStyle = "#0b171e";
  ctx.fillRect(-9, -9, 18, 18);
  ctx.restore();

  if (state.pulseTime > 0) {
    ctx.save();
    ctx.strokeStyle = `rgba(118, 239, 255, ${state.pulseTime * 1.5})`;
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.arc(p.x + p.w / 2, p.y + p.h / 2, 82 - state.pulseTime * 40, 0, Math.PI * 2);
    ctx.stroke();
    ctx.restore();
  }
}

function draw() {
  ctx.save();
  if (state.shake > 0) {
    ctx.translate((Math.random() - 0.5) * state.shake, (Math.random() - 0.5) * state.shake);
  }

  ctx.clearRect(0, 0, WIDTH, HEIGHT);
  const gradient = ctx.createLinearGradient(0, 0, 0, HEIGHT);
  gradient.addColorStop(0, "#08101f");
  gradient.addColorStop(0.55, "#071018");
  gradient.addColorStop(1, "#04070d");
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, WIDTH, HEIGHT);

  ctx.fillStyle = "rgba(180, 245, 255, 0.56)";
  state.stars.forEach((star) => ctx.fillRect(star.x, star.y, star.s, star.s * 2.1));

  ctx.strokeStyle = "rgba(118, 239, 255, 0.1)";
  ctx.lineWidth = 1;
  for (let x = 80; x < WIDTH; x += 80) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x - 80, HEIGHT);
    ctx.stroke();
  }

  state.cores.forEach((core) => {
    const x = core.x + Math.sin(core.wobble) * 8;
    ctx.save();
    ctx.translate(x, core.y);
    ctx.shadowColor = "#76efff";
    ctx.shadowBlur = 18;
    ctx.fillStyle = "#76efff";
    ctx.beginPath();
    ctx.arc(0, 0, core.r, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = "#f6ff80";
    ctx.beginPath();
    ctx.arc(0, 0, 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  });

  state.hazards.forEach((hazard) => {
    ctx.save();
    ctx.translate(hazard.x + hazard.w / 2, hazard.y + hazard.h / 2);
    ctx.rotate(hazard.rot);
    ctx.shadowColor = "#ff4160";
    ctx.shadowBlur = 14;
    ctx.fillStyle = "#ff4160";
    ctx.fillRect(-hazard.w / 2, -hazard.h / 2, hazard.w, hazard.h);
    ctx.fillStyle = "#ffc3ce";
    ctx.fillRect(-hazard.w / 2 + 5, -hazard.h / 2 + 5, hazard.w - 10, 4);
    ctx.restore();
  });

  drawPlayer();

  state.sparks.forEach((spark) => {
    const alpha = 1 - spark.age / spark.life;
    ctx.fillStyle = spark.color.replace(")", `, ${alpha})`).replace("rgb", "rgba");
    ctx.globalAlpha = alpha;
    ctx.fillRect(spark.x, spark.y, 3, 3);
    ctx.globalAlpha = 1;
  });

  if (state.mode === "paused") {
    ctx.fillStyle = "rgba(3, 6, 12, 0.58)";
    ctx.fillRect(0, 0, WIDTH, HEIGHT);
    ctx.fillStyle = "#ffffff";
    ctx.font = "800 48px system-ui";
    ctx.textAlign = "center";
    ctx.fillText("Paused", WIDTH / 2, HEIGHT / 2);
  }

  ctx.restore();

  scoreEl.textContent = Math.floor(state.score);
  bestScoreEl.textContent = state.best;
  shieldStatusEl.textContent = state.pulseCooldown <= 0 ? "Ready" : `${state.pulseCooldown.toFixed(1)}s`;
}

let last = performance.now();
function loop(now) {
  const dt = Math.min(0.033, (now - last) / 1000);
  last = now;
  update(dt);
  draw();
  requestAnimationFrame(loop);
}

startButton.addEventListener("click", resetGame);
restartButton.addEventListener("click", resetGame);

window.addEventListener("keydown", (event) => {
  const key = event.key.toLowerCase();
  if (["arrowleft", "arrowright", "a", "d", " ", "p", "enter"].includes(key)) {
    event.preventDefault();
  }
  if (key === " " || key === "spacebar") {
    pulse();
  } else if (key === "enter" && state.mode !== "playing") {
    resetGame();
  } else if (key === "p" && (state.mode === "playing" || state.mode === "paused")) {
    state.mode = state.mode === "paused" ? "playing" : "paused";
  } else {
    keys.add(key);
  }
});

window.addEventListener("keyup", (event) => {
  keys.delete(event.key.toLowerCase());
});

requestAnimationFrame(loop);
